<?php
namespace App\Repositories\Customers; use App\Models\Customers\CustomerGroup; use Illuminate\Contracts\Pagination\LengthAwarePaginator; use Illuminate\Support\Collection;
class CustomerGroupRepository { public function paginateForCompany(int $companyId):LengthAwarePaginator{return CustomerGroup::query()->withCount('members')->where('company_id',$companyId)->orderBy('sort_order')->paginate(15);} public function findForCompany(int $companyId,int $id,bool $trashed=false):CustomerGroup{return CustomerGroup::query()->where('company_id',$companyId)->when($trashed,fn($q)=>$q->withTrashed())->findOrFail($id);} public function options(int $companyId):Collection{return CustomerGroup::query()->where('company_id',$companyId)->where('is_active',true)->orderBy('sort_order')->get();} }
